#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5);//*uAspect.xy;

vec3 noiseVal =.03*(texture(sampler_noise_lq, vUv*.3+.01*rand_frame));
noiseVal = .01;
vec3 Feedback = GetBlur1(1-vUv);

vec2 zz = uv1 *uTexSize.xy *.015;
//zz =multiply(zz,mat2(_qa));
zz = zz.yx;
vec2 h1 = clamp(tan(zz.yx),-12,12) * cos(4*(q2+1)*zz);

vUv.xy += h1*uTexSize.zw * 4*(2+q1);


float r = texture(sampler_noise_hq,vUv/14).x*12;
vec2 uv6 = uv1;
uv6 = multiply(uv6, mat2(cos(r),sin(r),-sin(r),cos(r)));
vec3 mus = .1/(sqrt(uv6.y));

vec3 crisp = texture(sampler_main,vUv);
//crisp = mix(crisp.bgr,crisp.rgb,2*crisp);
ret = .995*crisp+noiseVal-.02;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv1 = (vUv-0.5)*uAspect.xy;

float rad2 = length(uv1) + .05;
float rad1 = .1/rad2 ;

vec2 uv2 = vec2 (vAngle/3.14, rad1*1.5);
uv2.y = uv2.y  +0.1*uTime;
uv2.x = uv2.x  +.02*uTime;

vec2 uv3 = vec2 (vAngle/3.14, rad1);
uv3.y = uv3.y  + q30 ;
uv3.x = uv3.x  + uTime/32;


vec3 crisp = GetPixel(uv2) + 2*GetPixel(uv3);
crisp += 2*GetBlur2(fract(uv2)) + 2*GetBlur2(fract(uv3));

vec3 lay1 = vec3 (1,0,1)*vUv.y*pow(1-vRadius,8);

crisp = 3*crisp * pow(vRadius,1);

float mask = clamp01(1-4*vRadius);

ret = crisp + lay1*mask + mask * GetPixel(vUv);


  fragColor = ret;
}
